			[22] = { str = "Voe pra Burning Steppes e entregue #INThe True Masters pt.5# quando pousar e aceite #GETThe True Masters pt.6#" },
			[23] = { str = "Suba ate #COORD[64,23]# e ouca ragged john depois volte ate #COORD[84,68]# e entregue #INThe True Masters pt.6# Eu PULO a proxima parte, faca depois se estiver preocupado com speed leveling. Foram 30k xp facil por nao fazer nada e sua cadeia de chave da ony esta iniciada.", x = 64, y = 23, zone = "Burning Steps" },
