------------56-57 Western Plaguelands
	--[511] = {
	[5657] = {
		title = "56-57 Western Plaguelands",
		--n = "56-57 Western Plaguelands",
		--pID = 510, nID = 512,
		--itemCount = 43,
		items = {
			[1] = { str = "56-57 Western Plaguelands" },
			[2] = { str = "Perto da cabana aceite #GETA Plague Upon Thee pt.1#" },
			[3] = { str = "Pegue o FP" },
			[3] = { str = "Sempre que voce voltar ao camp aqui verifique o vendor pela receita de stormshroud pants. Custa tipo 1.3g e voce pode facilmente vender por 10 ou 20g+ E uma receita limitada que restoca 1 por hora." },
			[4] = { str = "Va ate a tenda e entregue #INA Call To Arms: The Plaguelands!#, aceite #GETClear The Way#" },
			[5] = { str = "Va ate as 3 pessoas da Argent Dawn perto da outra tenda e entregue #INThe Everlook Report# e tambem complete #GETArgent Dawn Commission# nao e uma quest que voce tinha ela so usa pra te dar o trinket que voce deve sempre usar quando estiver em WPL e EPL porque da rep com AD e permite os scourge tokens droparem, ela tambem tem 3 quests novas de entrega desses. Voce provavelmente nao vai passar da primeira quest pois o resto sao mais de instancias." },
			[6] = { str = "Guarde os tokens ate eu mandar entregar" },
			[7] = { str = "Va pro NE ate #COORD[51,78]# e grinde os ghouls aqui ate ter o suficiente para #DOClear The Way#", x = 51, y = 78, zone = "Western Plaguelands" },
			[8] = { str = "Volte ate Chillwind Camp em #COORD[42,84]# e entregue #INClear The Way# aceite #GETAll Along the Watchtowers# e #GETThe Scourge Cauldrons#", x = 42, y = 84, zone = "Western Plaguelands" },
			[9] = { str = "Vire e entregue #INThe Scourge Cauldrons# aceite #GETTarget: Felstone Field#" },
			[10] = { str = "Voce deve estar agora a uns 5-10k do level 57" },
			[11] = { str = "Volte pro NE ate #COORD[48,72]# e passe pela ponte", x = 48, y = 72, zone = "Western Plaguelands" },
			[12] = { str = "Logo na cidade a esquerda em #COORD[47,71]# fica a 4a torre para #DOAll Along the Watchtowers#, tem elites dentro mas voce pode ficar fora de LOS na beirada e marcar as portas facilmente. 1a torre a Oeste daqui em #COORD[40,71]#. 2a torre NE daqui em #COORD[42,66]#. 3a torre NE daqui em #COORD[44,63]#. Logo atras dessa torre.", x = 47, y = 71, zone = "Western Plaguelands" },
			[13] = { str = "Va pro NW ate #COORD[37,56]# ate Felstone field, mate #NPCCauldron Lord Bilemaw# pela chave do caldeirao. Depois clique no caldeirao e entregue #INTarget: Felstone Field# aceite #GETReturn to Chillwind Camp#", x = 37, y = 56, zone = "Western Plaguelands" },
			[14] = { str = "Tem 2 casas no lado NE do campo em #COORD[38,54]#, entre na casa do norte e suba. Aceite #GETBetter Late Than Never pt.1#", x = 38, y = 54, zone = "Western Plaguelands" },
			[15] = { str = "Entre no celeiro ao lado e pegue a caixa no chao e entregue #INBetter Late Than Never pt.1# aceite #GETBetter Late Than Never pt.2#" },
			[16] = { str = "Volte ate Chillwind Camp em #COORD[42,84]# e entregue #INAll Along the Watchtowers#, aceite #GETScholomance# PULE a outra a menos que consiga umas 10-20 pessoas.", x = 42, y = 84, zone = "Western Plaguelands" },
			[17] = { str = "Entregue #INScholomance# logo atras dele, aceite #GETSkeletal Fragments Bones# isso vai demorar um pouco e dropa de qualquer esqueleto." },
			[18] = { str = "Perto do FP entregue #INReturn to Chillwind Camp# aceite #GETTarget: Dalson's Tears#" },
			[19] = { str = "Suba ate #COORD[46,52]# ate Dalson'Tears, mate #NPCCauldron Lord Malvinious# pela chave do caldeirao. Depois clique no caldeirao e entregue #INTarget: Dalson's Tears# aceite #GETReturn to Chillwind Camp#", x = 46, y = 52, zone = "Western Plaguelands" },
			[20] = { str = "Entre no celeiro aqui em #COORD[47,50]# e toque no diario no chao e complete, mais uma quest que nao e quest.", x = 47, y = 50, zone = "Western Plaguelands" },
			[21] = { str = "Va atras do celeiro e procure um Wandering Skeleton e pegue a Dalson Outhouse Key dele. Use pra abrir a casinha atras aqui e mate Farmer Dalson e pegue a Dalson Cabinet Key dele. Use a chave no armario trancado la em cima na casa em #COORD[47,49]# perto do celeiro e complete a quest #INLocked Away#", x = 47, y = 49, zone = "Western Plaguelands" },
			[22] = { str = "Volte ate Chillwind Camp em #COORD[42,84]# e entregue #INReturn to Chillwind Camp# aceite #GETTarget: Writhing Haunt#", x = 42, y = 84, zone = "Western Plaguelands" },
			[23] = { str = "Use Hearthstone pra IF depois voe pra SW" },
			[24] = { str = "Va ate o predio em #COORD[48,30]# no 2o andar da area da catedral e entregue #INBetter Late Than Never pt.2# aceite #GETGood Natured Emma#", x = 48, y = 30, zone = "Stormwind" },
			[25] = { str = "Emma anda entre a catedral e o trade district, ache ela e entregue #INGood Natured Emma# aceite #GETGood Luck Charm#" },
			[26] = { str = "Entre no keep em #COORD[78,17]# e aceite #GETThe First and the Last#", x = 78, y = 17, zone = "Stormwind" },
			[27] = { str = "Va ate #COORD[75,79]# e entregue #INThe First and the Last# aceite #GETHonor the Dead# depois entregue de volta, aceite #GETFlint Shadowmore#", x = 75, y = 79, zone = "Stormwind" },
			[28] = { str = "Voe de volta pra WPL" },
			[29] = { str = "Na frente da casa entregue #INFlint Shadowmore# aceite #GETThe Eastern Plagues#" },
			[30] = { str = "Volte ate Felstone field na casa la em cima em #COORD[38,54]# e entregue #INGood Luck Charm# aceite #GETTwo Halves Become One# Va la fora e procure um jabbering ghoul. Voce nao tem como errar ele carrega um forcado. Continue limpando na frente da casa ate achar. Isso vai dar um bom tempo pra pegar os skeletal fragments", x = 38, y = 54, zone = "Western Plaguelands" },
			[31] = { str = "Combine as metades e volte la em cima e entregue #INTwo Halves Become One#" },
			[32] = { str = "Va pro SE ate #COORD[53,65]# ate Writhing Haunt, mate #NPCCauldron Lord Razarch# pela chave do caldeirao. Depois clique no caldeirao e entregue #INTarget: Writhing Haunt# aceite #GETReturn to Chillwind Camp#", x = 53, y = 65, zone = "Western Plaguelands" },
			[33] = { str = "Na casa em #COORD[54,65]# aceite #GETThe Wildlife Suffers Too pt.1# agora va ao norte do haunt e mate os lobos doentes. Nao va mais pra leste pra achar esses so va pro Norte, talvez um pouco NW.", x = 54, y = 65, zone = "Western Plaguelands" },
			[34] = { str = "Volte ate #COORD[54,65]# e entregue #INThe Wildlife Suffers Too pt.1# aceite #GETThe Wildlife Suffers Too pt.2#", x = 54, y = 65, zone = "Western Plaguelands" },
			[35] = { str = "Volte ate Chillwind Camp em #COORD[42,84]# e entregue #INReturn to Chillwind Camp# aceite #GETTarget: Gahrron's Withering#", x = 42, y = 84, zone = "Western Plaguelands" },
			[36] = { str = "Va logo ao norte do Writhing Haunt entre as montanhas no mapa, #COORD[52,56]# e mate diseased grizzleys no caminho descendo ate #COORD[62,58]# para #DOThe Wildlife Suffers Too pt.2#", x = 52, y = 56, zone = "Western Plaguelands" },
			[37] = { str = "Va pro NE ate #COORD[62,58]# ate Gahrron's Withering, mate #NPCCauldron Lord Soulwrath# pela chave do caldeirao. Depois clique no caldeirao e entregue #INTarget: Gahrron's Withering# aceite #GETReturn to Chillwind Camp#", x = 62, y = 58, zone = "Western Plaguelands" },
			[38] = { str = "Volte ate #COORD[54,65]# e entregue #INThe Wildlife Suffers Too pt.2# aceite #GETGlyphed Oaken Branch#", x = 54, y = 65, zone = "Western Plaguelands" },
			[39] = { str = "Se voce ainda nao terminou Skeletal Fragments va ate a cripta em #COORD[54,79]# e mate os esqueletos ate ter 15 fragments", x = 54, y = 79, zone = "Western Plaguelands" },
			[40] = { str = "Volte ate Chillwind Camp em #COORD[42,84]# e entregue #INReturn to Chillwind Camp#", x = 42, y = 84, zone = "Western Plaguelands" },
			[41] = { str = "Vire pro cara na frente da tenda, e complete a quest #INMission Accomplished!# sem link porque nao e uma quest de novo lol. Agora veja que ir e voltar pareceu fora do caminho mas teve um boost grande de xp no final, e bom xp durante todo o processo." },
			[42] = { str = "A sua direita entregue #INSkeletal Fragments# PULE a proxima parte a menos que queira comecar sua chave de scholo." },
			[43] = { str = "Va pro leste ate #COORD[70,50]# e entre em Eastern Plaguelands (EPL)", x = 70, y = 50, zone = "Western Plaguelands" },
		}
	},

