			[4] = { str = "Daqui pra baixo ate a area maior, mate qualquer cachorro, verme, e morcego. Foque neles enquanto vai pro proximo passo" },
			[5] = { str = "Continue matando os cachorros e morcegos e va ate o esqueleto em #COORD[28,74]# abra e pegue a insignia para #DOThe Eastern Plagues# depois suba um pouco mais ate o proximo esqueleto em #COORD[27,74]# e pegue a insignia, ta praticamente na frente dele e voce tambem vai receber a mensagem de blightcaller found. Agora desca perto da estrada ate #COORD[28,79]# e loote a ultima insignia do esqueleto", x = 28, y = 74, zone = "Eastern Plaguelands" },
			[6] = { str = "Foque nos cachorros e morcegos enquanto vai ate Darrowshire em #COORD[36,90]# na casa destruida. Entregue #INSister Pamela# aceite #GETPamela's Doll# depois va ate as casas aqui, em qualquer uma das casas pode ter qualquer uma das 3 partes da boneca. Sao aleatorias. Fantasmas spawnam quando voce chega perto das partes entao fique atento. Depois de ter as 3 partes combine e volte ate #COORD[36,90]# e entregue #INPamela's Doll# aceite #GETAuntie Marlene# e #GETUncle Carlin#", x = 36, y = 90, zone = "Eastern Plaguelands" },
			[7] = { str = "Olhe no seu mapa em #COORD[48,76]# Isso alinha com aquela montanha do meio. Nao passe desse ponto pro leste ate ter seus kills de plaguehound runt para #DODemon Dogs# e plaguebats para #DOBlood Tinged Skies# porque nao tem nenhum depois desse ponto.", x = 48, y = 76, zone = "Eastern Plaguelands" },
			[8] = { str = "Nao esqueca de matar os grubs pelo caminho tambem para #DOCarrion Grubbage#, eles nao sao tao importantes porque estao por toda parte." },
			[9] = { str = "Mate Plaguehounds para Demon Dogs ao redor de #COORD[56,57]# isso e ao norte do scar e ao sul de blackwood lake. Nao esqueca dos grubs", x = 56, y = 57, zone = "Eastern Plaguelands" },
			[10] = { str = "Mate Frenzied Plaguehounds para #DODemon Dogs# ao redor de #COORD[61,41]# isso e ao norte de blackwood lake mas agora a oeste dela.", x = 61, y = 41, zone = "Eastern Plaguelands" },
			[11] = { str = "Va ate lights hope chapel em #COORD[81,58]# se voce ainda precisar de grub meat para #DOCarrion Grubbage#, entao mate eles enquanto vai", x = 81, y = 58, zone = "Eastern Plaguelands" },
			[12] = { str = "Pegue o FP" },
			[13] = { str = "Entregue #INUncle Carlin# aceite #GETDefenders of Darrowshire#" },
			[14] = { str = "Vire e entregue #INDuke Nicholas Zverenhoff#" },
			[15] = { str = "Va pro SW ate #COORD[79,63]# e aceite #GETZaeldarr the Outcast#", x = 79, y = 63, zone = "Eastern Plaguelands" },
			[16] = { str = "Voe de volta pra EPL" },
			[17] = { str = "Na frente da casa entregue #INThe Eastern Plagues# aceite #GETThe Blightcaller Cometh#" },
			[18] = { str = "Se voce estiver a 6.600 de upar entao use Hearthstone pra IF e voe pra SW, se nao grinde ate estar nessa faixa." },
			[19] = { str = "Va ate #COORD[78,18]# no keep e entregue #INThe Blightcaller Cometh# agora eu PULO a proxima parte mas e uma boa quest pra fazer no 60", x = 78, y = 18, zone = "Eastern Plaguelands" },
			[18] = { str = "Va pegar novas skills" },
			[19] = { str = "Voe de volta pra WPL" },
		}
	},

-----------58-58 Western Plaguelands
	--[513] = {
	[5857] = {
		title = "58-58 Western Plaguelands",
		--n = "58-58 Western Plaguelands",
		--pID = 512, nID = 514,
		--itemCount = 9,
		items = {
			[1] = { str = "58-58 Western Plaguelands" },
			[2] = { str = "Va pro NE ate a casa em #COORD[49,78]# e suba. Entregue #INPamela's Doll# aceite #GETA Strange Historian#", x = 49, y = 78, zone = "Western Plaguelands" },
			[3] = { str = "Logo ao norte da casa em #COORD[49,76]# voce vai ver uma lapide de cor diferente. Loote e pegue o anel de casamento para #DOA Strange Historian#", x = 49, y = 76, zone = "Western Plaguelands" },
			[4] = { str = "Entre pela entrada oeste de Andorhal em #COORD[39,71]# e voce deve ver o unico predio inteiro, parece um Inn em #COORD[39,68]#. Suba e entregue #INA Strange Historian# aceite #GETThe Annals of Darrowshire# tambem aceite #GETA Matter of Time#", x = 39, y = 68, zone = "Western Plaguelands" },
			[5] = { str = "Agora procure ao redor da cidade aqui por silos quebrados com uma luz azul saindo deles. Use o silo horn pra invocar os vermes, spawna 1-3 mobs para #DOA Matter of Time#. Depois de matar o ultimo eles tendem a spawnar outro. Tem mais no lado Leste da cidade" },
			[6] = { str = "Va ate o Town Hall perto de todos os mobs no meio da cidade, voce pode entrar sorrateiramente pelo lado SW. Pegue os livros no chao ate pegar #GETThe Annals of Darrowshire# Alguns vao spawnar mobs" },
			[7] = { str = "Volte ate o Inn em #COORD[39,68]# e no ultimo andar, entregue #INA Matter of Time# aceite #GETCounting Out Time# tambem entregue #INThe Annals of Darrowshire# aceite #GETBrother Carlin#", x = 39, y = 68, zone = "Western Plaguelands" },
			[8] = { str = "Va la fora e procure ao redor das casas quebradas por pequenas lancheiras de metal para #DOCounting Out Time#" },
			[9] = { str = "Volte ate o Inn em #COORD[39,68]# e entregue #INCounting Out Time# voce agora pode repetir essa quest por um dampener. Isso e usado contra o elite 61", x = 39, y = 68, zone = "Western Plaguelands" },
		}
	},

-----------58-58 Eastern Plaguelands
	--[514] = {
	[5858] = {
		title = "58-58 Eastern Plaguelands",
		--n = "58-58 Eastern Plaguelands",
		--pID = 513, nID = 515,
		--itemCount = 18,
		items = {
			[1] = { str = "58-58 Eastern Plaguelands" },
			[2] = { str = "Saia daqui e entre em EPL suba pro NW ate 7,43 e entregue as 3 quests #INDemon Dogs# #INBlood Tinged Skies# e #INCarrion Grubbage# aceite #GETRedemption# depois ouca ele e entregue de volta. Depois aceite #GETOf Forgotten Memories#", x = 7, y = 43, zone = "Eastern Plaguelands" },
			[3] = { str = "Va ate o Undercroft em #COORD[28,86]# e va atras dele. Toque na pilha de terra pra invocar Mercutio e 3 guardas. O jeito mais facil de fazer isso e kitar ele pra longe dos amigos ou pegar um grupo. Loote o corpo dele pelo martelo para #DOOf Forgotten Memories#", x = 28, y = 86, zone = "Eastern Plaguelands" },
			[4] = { str = "Agora va ate o fundo da cripta e mate o troll bem grande para #DOZaeldarr the Outcast# So pegue o scroll no chao se quiser" },
			[5] = { str = "Volte ate 7,43 e entregue #INOf Forgotten Memories# aceite #GETOf Lost Honor#", x = 7, y = 43, zone = "Eastern Plaguelands" },
			[6] = { str = "Va ate Light's Hope Chapel ou volte pra Chillwind e voe ate la" },
			[7] = { str = "Entregue #INBrother Carlin# aceite #GETVillains of Darrowshire#" },
			[8] = { str = "Desca ate #COORD[79,63]# e entregue #INZaeldarr the Outcast#", x = 79, y = 63, zone = "Eastern Plaguelands" },
			[9] = { str = "Desca logo ao Norte de Corin's Crossing ate #COORD[53,65]# e pegue a espada para #DOVillains of Darrowshire# Esta la no scar. Nao esqueca de fazer um pouco de #DODefenders of Darrowshire# em Corin's. So pegue o que puder", x = 53, y = 65, zone = "Eastern Plaguelands" },
			[10] = { str = "Va ao norte ate Blackwood Lake em #COORD[51,49]# e pegue o cranio debaixo d'agua para #DOVillains of Darrowshire#", x = 51, y = 49, zone = "Eastern Plaguelands" },
			[11] = { str = "Va pro NE ate #COORD[65,41]# e mate os zumbis para parte de #DODefenders of Darrowshire# tem bastante aqui voce provavelmente pode terminar", x = 65, y = 41, zone = "Eastern Plaguelands" },
			[12] = { str = "Va ate o lago em #COORD[71,33]# e pegue a bandeira perto da jaula, e dificil de ver e esta deitada para #DOOf Lost Honor#", x = 71, y = 33, zone = "Eastern Plaguelands" },
			[13] = { str = "Va pro NW ate a torre em #COORD[56,24]# e entregue #INTroubled Spirits of Kel'Theril# PULE a proxima parte", x = 56, y = 24, zone = "Eastern Plaguelands" },
			[14] = { str = "Va pro Oeste ate #COORD[45,34]# e loote os montes de cupim aqui para #DOA Plague Upon Thee pt.1# ate ter 100 cupins, tambem mate ghouls pra terminar #DODefenders of Darrowshire#", x = 45, y = 34, zone = "Eastern Plaguelands" },
			[15] = { str = "Va ate Lights Hope Chapel agora" },
			[16] = { str = "Va perto da tenda e entregue #INDefenders of Darrowshire# e #INVillains of Darrowshire#" },
			[17] = { str = "Voe pra WPL" },
			[18] = { str = "Perto da casa entregue #INA Plague Upon Thee pt.1# aceite #GETA Plague Upon Thee pt.2#" },
		}
	},

------------58-59 Western Plaguelands
	--[515] = {
	[5859] = {
		title = "58-59 Western Plaguelands",
		--n = "58-59 Western Plaguelands",
		--pID = 514, nID = 516,
		--itemCount = 19,
		items = {
			[1] = { str = "58-59 Western Plaguelands" },
			[2] = { str = "Suba ate #COORD[51,28]# e aceite #GETUnfinished Business pt.1#", x = 52, y = 30, zone = "Western Plaguelands" },
			[3] = { str = "Comece voltando pro SW ao redor de #COORD[47,32]# e limpe o caminho ate o moinho. Clique na caixa e coloque os cupins, depois clique no barril e entregue #INA Plague Upon Thee pt.2# aceite #GETA Plague Upon Thee pt.3#", x = 47, y = 32, zone = "Western Plaguelands" },
			[4] = { str = "Va logo ao sul de #COORD[49,42]# e mate 2 knights e mages para #DOUnfinished Business pt.1# depois #COORD[51,43]# para os hunters e medics", x = 49, y = 42, zone = "Western Plaguelands" },
			[5] = { str = "Va ate #COORD[51,28]# e entregue #INUnfinished Business pt.1# aceite #GETUnfinished Business pt.2#", x = 51, y = 28, zone = "Western Plaguelands" },
			[6] = { str = "Va ate #COORD[57,36]# e mate Huntsman Radly para #DOUnfinished Business pt.2# depois ao norte ate a torre em #COORD[55,23]# e mate Cavalier Durgen no topo", x = 57, y = 36, zone = "Western Plaguelands" },
			[7] = { str = "Saia direto da torre pelas montanhas ate #COORD[51,28]# e entregue #INUnfinished Business pt.2# fazer a 3a parte #DOUnfinished Business pt.3# e opcional. Algumas classes conseguem mais facil que outras. Voce tem que ir ao norte ate hearthglen e subir na torre grande no centro da cidade em #COORD[45,18]# e olhar pela beirada ate dizer completo.", x = 45, y = 18, zone = "Western Plaguelands" },
			[8] = { str = "Volte direto pro sul pelas montanhas ate #COORD[51,28]# e entregue #INUnfinished Business pt.3#", x = 51, y = 28, zone = "Western Plaguelands" },
			[9] = { str = "Entre em EPL e suba ate 7,43 e entregue #INOf Lost Honor# aceite #GETOf Love and Family pt.1#", x = 7, y = 43, zone = "Eastern Plaguelands" },
			[10] = { str = "Volte pra WPL e va/nade ate a ilha onde fica Scholo em #COORD[65,75]# e entregue #INOf Love and Family pt.1# PULE o resto ate voce fazer strat", x = 65, y = 75, zone = "Western Plaguelands" },
			[11] = { str = "Volte ate Chillwind Camp em #COORD[43,84]# e entregue #INA Plague Upon Thee pt.3#", x = 43, y = 84, zone = "Western Plaguelands" },
			[12] = { str = "Agora voce quer fazer 2 coisas aqui. Ficar friendly com Argent Dawn e ficar a 8-8.5k de upar. Voce pode fazer #DOAlas, Andorhal# se achar um grupo, nao e tao dificil mas pode precisar de 5-10 pessoas. Isso vai dar 8300 xp facil ao inves de grindar." },
			[13] = { str = "Agora voce quer ir ate andorhal e grindar ate ficar friendly, uma vez friendly volte pra Chillwind Camp e entregue todos seus scourge tokens. Isso permite voce comprar mana biscuits que restauram mana e vida e mais que comida normal. Se voce ainda precisar upar entao va grindar nos mobs em andorhal de novo ate estar 8-8.5k do level 59" },
			[14] = { str = "Quando estiver a 8k-8.5k de upar, voe pra Hinterlands e va todo o caminho pro NE ate a cachoeira em #COORD[80,46]# e pule. Debaixo d'agua loote o bau e termine #DOCortello's Riddle pt.3#", x = 80, y = 46, zone = "The Hinterlands" },
			[15] = { str = "Use Hearthstone pra IF" },
			[16] = { str = "Va ate a sala do trono em #COORD[43,52]# e aceite #GETAn Earnest Proposition# (escolha sua classe da lista) Voce precisa ter os bracers tier 0 da sua classe pra fazer essa quest. Voce pode comprar na AH", x = 43, y = 52, zone = "Ironforge" },
			[17] = { str = "Voe pra Menethil e pegue o barco pra Auberdine, voe pra Darnassus" },
			[18] = { str = "Va ate 35,8 no 2o andar e entregue #INGlyphed Oaken Branch#", x = 35, y = 8, zone = "Darnassus" },
			[19] = { str = "Voce deve estar level 59, voe pra Winterspring" },
		}
	},

------------59-60 Winterspring
	--[516] = {
	[5960] = {
		title = "59-60 Winterspring",
		--n = "59-60 Winterspring",
		--pID = 515, nID = 516,
		--itemCount = 31,
		items = {
			[1] = { str = "59-60 Winterspring" },
			[2] = { str = "A sua esquerda ao entrar entregue #INAre We There, Yeti? pt.3#" },
			[3] = { str = "Perto do fundo tem 2 hordes, aceite #GETLuck Be With You#" },
			[4] = { str = "Vire e entregue #INFelnok Steelspring# aceite #GETChillwind Horns#" },
			[5] = { str = "Faca #DOAn Earnest Proposition# so mate os sabers ate ter 15 blood" },
			[6] = { str = "Va logo pro SE daqui ao redor de #COORD[55,18]# e mate as chimeras para #DOChillwind Horns#", x = 55, y = 18, zone = "Winterspring" },
			[7] = { str = "Va ate Starfall Village em #COORD[52,30]# e aceite #GETEnraged Wildkin pt.1#", x = 52, y = 30, zone = "Winterspring" },
			[8] = { str = "Entregue #INChillwind Horns# PULE a outra a menos que queira ir la" },
			[9] = { str = "Va ao sul ate #COORD[59,59]# e toque na caixa e entregue #INEnraged Wildkin pt.1# aceite #GETEnraged Wildkin pt.2#", x = 59, y = 59, zone = "Winterspring" },
			[10] = { str = "Volte ate a estrada em #COORD[61,60]# e toque na carroça, entregue #INEnraged Wildkin pt.2# aceite #GETEnraged Wildkin pt.3# pegue a caixa na neve", x = 61, y = 60, zone = "Winterspring" },
			[11] = { str = "Va pro leste de novo ate #COORD[63,59]# e entregue #INFind Ranshalla# aceite #GETGuardians of the Altar#", x = 63, y = 59, zone = "Winterspring" },
			[12] = { str = "Agora proteja ela enquanto faz o que precisa. Certifique-se de pegar a pena de um owl para #DOEnraged Wildkin pt.3# Quando ela parar numa caverna, acenda a tocha pra ela. Se voce nao pegar a pena antes de terminar continue matando ate conseguir." },
			[13] = { str = "Va ao sul ate #COORD[62,69]# e loote as gemas para #DOLuck Be With You# hunters e locks podem usar pet pra distrair mobs enquanto loota, outras classes vao ter que grupar.", x = 62, y = 69, zone = "Winterspring" },
			[14] = { str = "Use Hearthstone pra Everlook" },
			[15] = { str = "Entregue #INLuck Be With You# nos 2 hordes perto do fundo de everlook" },
			[16] = { str = "Voce deve estar uns 25% no level 59 agora." },
			[17] = { str = "Aceite #GETCache of Mau'Ari# se quiser. Isso so te da um item que permite os mobs aqui droparem coisas que voce pode entregar por buffs" },
			[18] = { str = "Suba ate Starfall Village em #COORD[52,30]# e entregue #INEnraged Wildkin pt.3#", x = 52, y = 30, zone = "Winterspring" },
			[19] = { str = "Va ate #COORD[31,45]# e entregue #INMystery Goo# aceite #GETToxic Horrors#", x = 31, y = 45, zone = "Winterspring" },
			[20] = { str = "Entre em Felwood e va ate #COORD[48,24]# e mate toxic horrors para #DOToxic Horrors# esses tambem dropam essence of waters", x = 48, y = 24, zone = "Felwood" },
			[21] = { str = "Voe pra Rut'theran Village e va ate a casa em #COORD[55,92]# e entregue #INGuardians of the Altar# aceite #GETWildkin of Elune#", x = 55, y = 92, zone = "Teldrassil" },
			[22] = { str = "Entre em Darnassus e suba ate o topo da torre em 34,8 e entregue #INWildkin of Elune#", x = 34, y = 8, zone = "Darnassus" },
			[23] = { str = "Voe de volta pra Felwood" },
			[24] = { str = "Volte subindo ate Winterspring e va ate #COORD[31,45]# entregue #INToxic Horrors# aceite #GETWinterfall Runners#", x = 31, y = 45, zone = "Winterspring" },
			[25] = { str = "Agora pra achar os runners. Eles viajam de qualquer lugar da Timbermaw Cave pro leste ate #COORD[53,34]# depois ao redor das montanhas ao norte de everlook ate Winterfall Village. Se voce nao viu eles da caverna ate aqui, va pro leste. Voce nao precisa matar todos os 3", x = 53, y = 34, zone = "Winterspring" },
			[26] = { str = "Depois de pegar a caixa volte ate #COORD[31,45]# Entregue Winterfall Runners uma emboscada vai vir do lago, se voce nao sair da tenda eles nao vao dar aggro. PULE a proxima parte a menos que consiga grupo", x = 31, y = 45, zone = "Winterspring" },
			[27] = { str = "Use Hearthstone pra Everlook" },
			[28] = { str = "Voce deve estar 45-50% no level 59. Agora eu me certifico que tenho meus mana bisquits e comeco a grindar ate estar a 6600 do level 60. Qualquer lugar serve onde tem bastante mob. E tudo questao de preferencia. Eu escolho o owl wing thicket em #COORD[64,62]# ou qualquer coisa ao norte de everlook. Eu gosto de matar furlbogs por rep de timbermaw tambem.", x = 64, y = 62, zone = "Winterspring" },
			[29] = { str = "Se voce nao quiser grindar essa quantidade grande entao faca BRD, scholo, ou strat. Voce tem muitas quests nesses lugares pra fazer" },
			[30] = { str = "Quando estiver a 6600 do 60 va pra IF e entregue #INAn Earnest Proposition#" },
			[31] = { str = "Parabens pelo 60!" },
		}
	},
}
